import { SurveyModel, LocalizableString, RendererFactory, addIconsToThemeSet, SvgRegistry, checkLibraryVersion, PopupModalManager, settings, CssClassBuilder, Helpers, createSvg, PopupSurveyModel, ScrollViewModel, doKey2ClickUp, createPopupViewModel, Question, doKey2ClickBlur, doKey2ClickDown, ActionDropdownViewModel, SurveyProgressModel, ProgressButtonsResponsivityManager, ButtonGroupItemModel, unwrap, Serializer } from 'survey-core';
import { editableStringRendererName, RowViewModel, QuestionAdornerViewModel, QuestionDropdownAdornerViewModel, QuestionImageAdornerViewModel, QuestionRatingAdornerViewModel, PageAdorner, LogoImageViewModel, editorLocalization, ItemValueWrapperViewModel, ImageItemValueWrapperViewModel, MatrixCellWrapperViewModel, StringEditorViewModelBase, initLogicOperator, ToolboxToolViewModel, PageNavigatorViewModel, SurveyResultsModel, assign, SurveyCreatorModel } from 'survey-creator-core';

class Logger {
    constructor(prefix) {
        this.isDisposed = false;
        this.prefix = prefix;
    }
    startMethod(name) {
        console.debug(`${this.prefix} - start ${name}`);
    }
    endMethod(name) {
        console.debug(`${this.prefix} - end ${name}`);
    }
    startSection(name) {
        console.debug(`${this.prefix} - section ${name}`);
    }
    endSection(name) {
        console.debug(`${this.prefix} - end section ${name}`);
    }
    error(err) {
        console.error(`${this.prefix} -`, err);
    }
    dispose() {
        this.isDisposed = true;
        console.debug(`${this.prefix} - disposed`);
    }
}

